CustomField.formula:
if( isblank( DaysSinceLastActivity__c ),
  "未接触",
  if( DaysSinceLastActivity__c < 30,
    image("/img/samples/light_green.gif", "1ヶ月以内"),
    if(  DaysSinceLastActivity__c < 60,
      image("/img/samples/light_yellow.gif", "2ヶ月以内"),
      image("/img/samples/light_red.gif", "2ヶ月放置")
    )
  )
)
